const tz = $env.TIMEZONE || 'Asia/Kolkata';
const hour = parseInt(new Date().toLocaleString('en-GB', { timeZone: tz, hour: '2-digit', hour12: false }), 10);
let slot = 'morning';
if (hour >= 12 && hour < 17) slot = 'afternoon';
else if (hour >= 17) slot = 'evening';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const items = $input.all().filter(item => item.json.id && item.json.send_slot === slot);
if (!items.length) return [{ json: { _skip: true, reason: `No ${slot} medicine reminders due`, slot, todayStr } }];
function envSid(key) { return ($env[key] || '').trim(); }
function varsFor(row) {
  const patient = row.patient_name || 'there';
  const doctor = row.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor';
  const clinic = row.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic';
  const medicine = row.medicine_name || 'your medicine';
  const courseDays = String(row.course_days || '');
  const template = row.template_id || '';
  if (template.includes('day1_morning') || template.includes('reminder_night')) return { '1': patient, '2': medicine };
  if (template.includes('last_day')) return { '1': patient, '2': courseDays, '3': doctor, '4': medicine };
  if (template.includes('day1_evening') || template.includes('reminder_morning') || template.includes('journey_daily')) return { '1': patient, '2': medicine, '3': doctor };
  if (template.includes('midpoint')) return { '1': patient, '2': clinic, '3': courseDays };
  if (template.includes('complete')) return { '1': patient, '2': courseDays, '3': doctor };
  if (template.includes('reminder_afternoon')) return { '1': patient, '2': medicine, '3': clinic };
  return { '1': patient, '2': medicine };
}
const mapped = items.map(item => {
  const row = item.json;
  const sid = envSid(row.content_env_key);
  const phone = row.phone;
  if (!sid || !phone || !/^\+[1-9]\d{6,14}$/.test(phone)) return { json: { ...row, _skip: true, reason: 'Missing template SID or phone' } };
  return { json: { ...row, _skip: false, _workflow: 'workflow-14-medicine-journey', _message_type: row.message_type, _scheduled_date: todayStr, _to_phone: 'whatsapp:' + phone, _content_sid: sid, _content_variables: JSON.stringify(varsFor(row)), _schedule_id: row.id } };
}).filter(item => !item.json._skip);
if (!mapped.length) return [{ json: { _skip: true, reason: `No valid ${slot} medicine reminders due`, slot, todayStr } }];
return mapped;
